import{_ as i,o as e,c as t,S as o}from"./chunks/framework.DZlzLDBr.js";const u=JSON.parse('{"title":"Anki Export & Import","description":"","frontmatter":{},"headers":[],"relativePath":"Anki-Export-&-Import.md","filePath":"Anki-Export-&-Import.md","lastUpdated":null}'),r={name:"Anki-Export-&-Import.md"};function l(n,a,s,p,d,c){return e(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="anki-export-import" tabindex="-1">Anki Export &amp; Import <a class="header-anchor" href="#anki-export-import" aria-label="Permalink to &quot;Anki Export &amp; Import&quot;">​</a></h1><p>Last modified: 13/02/2026</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Sprout can import from and export to Anki using <code>.apkg</code> files. Use the command palette:</p><ul><li><strong>Export to Anki (.apkg)</strong></li><li><strong>Import from Anki (.apkg)</strong></li></ul><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p>Anki import/export is experimental.</p></div><h2 id="export-to-anki-apkg" tabindex="-1">Export to Anki (.apkg) <a class="header-anchor" href="#export-to-anki-apkg" aria-label="Permalink to &quot;Export to Anki (.apkg)&quot;">​</a></h2><ol><li>Run <strong>Export to Anki (.apkg)</strong>.</li><li>Choose what to export: <ul><li>all cards</li><li>cards in a group</li><li>current note</li></ul></li><li>Choose options: <ul><li>MCQ handling (convert to Basic or skip)</li><li>include scheduling data</li><li>include review history</li><li>include media files</li><li>default deck name</li></ul></li><li>Save or download the <code>.apkg</code>.</li></ol><h3 id="important-limits" tabindex="-1">Important limits <a class="header-anchor" href="#important-limits" aria-label="Permalink to &quot;Important limits&quot;">​</a></h3><ul><li>Image Occlusion cards are not exported.</li><li>Cloze child cards are not exported.</li><li>If you skip MCQ cards, they are not included in the package.</li></ul><h2 id="fsrs-after-export" tabindex="-1">FSRS after export <a class="header-anchor" href="#fsrs-after-export" aria-label="Permalink to &quot;FSRS after export&quot;">​</a></h2><p>Sprout includes FSRS parameters and card memory state in the export. Anki still requires you to manually enable FSRS because that switch is global in Anki.</p><p>After import into Anki:</p><ol><li>Open deck options.</li><li>Find <strong>FSRS</strong>.</li><li>Turn FSRS on.</li></ol><h2 id="import-from-anki-apkg" tabindex="-1">Import from Anki (.apkg) <a class="header-anchor" href="#import-from-anki-apkg" aria-label="Permalink to &quot;Import from Anki (.apkg)&quot;">​</a></h2><ol><li>Run <strong>Import from Anki (.apkg)</strong>.</li><li>Select the <code>.apkg</code> and review preview details.</li><li>Set options: <ul><li>target folder</li><li>import as new vs preserve scheduling</li><li>deck/tag to group mapping</li><li>duplicate handling</li></ul></li><li>Start import and check the summary.</li></ol><h3 id="important-limits-and-conversions" tabindex="-1">Important limits and conversions <a class="header-anchor" href="#important-limits-and-conversions" aria-label="Permalink to &quot;Important limits and conversions&quot;">​</a></h3><ul><li>Image Occlusion cards are skipped on import.</li><li>Note types other than Basic/Cloze are imported as Basic.</li></ul><h3 id="failure-cases-to-watch" tabindex="-1">Failure cases to watch <a class="header-anchor" href="#failure-cases-to-watch" aria-label="Permalink to &quot;Failure cases to watch&quot;">​</a></h3><ul><li>Invalid or damaged <code>.apkg</code> files can fail to import.</li><li>Duplicate handling can skip cards you expected to see.</li><li>If deck/tag mapping is wrong, cards may end up in unexpected groups.</li></ul><h2 id="before-large-imports" tabindex="-1">Before large imports <a class="header-anchor" href="#before-large-imports" aria-label="Permalink to &quot;Before large imports&quot;">​</a></h2><p>Create a backup first in <a href="./Backups">Backups</a> so you can roll back if needed.</p>',22)])])}const h=i(r,[["render",l]]);export{u as __pageData,h as default};
